mapper.select:
SELECT AVG(i.traffic) as ave_flow, AVG(i.pressure) as ave_pressure, AVG(i.temperature) as ave_temperature, AVG(i.shake) as ave_vibration, UNIX_TIMESTAMP(DATE(i.create_time)) * 1000 as time FROM inspection i INNER JOIN sensor s ON i.sensor_id = s.id
AND s.pipeline_id = #{id}
AND s.pipe_segment_id = #{segmentId}
AND s.pipe_segment_id IN
#{segmentIdItem}
AND i.create_time >= FROM_UNIXTIME(#{startTime}/1000)
AND i.create_time <= FROM_UNIXTIME(#{endTime}/1000)
GROUP BY DATE(i.create_time), time ORDER BY DATE(i.create_time)

SELECT id, pipe_id AS pipeId, segment_order AS segmentOrder FROM pipe_segment WHERE pipe_id = #{pipeId} AND id IN
#{segmentId}
ORDER BY segment_order

SELECT AVG(i.temperature) as ave_temperature, CASE WHEN AVG(i.temperature) < 20 THEN 0 WHEN AVG(i.temperature) < 50 THEN 1 WHEN AVG(i.temperature) < 80 THEN 2 ELSE 3 END as temperature_status,
AVG(i.traffic) as ave_flow, CASE WHEN AVG(i.traffic) < 10 THEN 0 WHEN AVG(i.traffic) < 30 THEN 1 WHEN AVG(i.traffic) < 50 THEN 2 ELSE 3 END as flow_status,
AVG(i.pressure) as ave_pressure, CASE WHEN AVG(i.pressure) < 5 THEN 0 WHEN AVG(i.pressure) < 15 THEN 1 WHEN AVG(i.pressure) < 25 THEN 2 ELSE 3 END as pressure_status,
AVG(i.shake) as ave_vibration, CASE WHEN AVG(i.shake) < 2 THEN 0 WHEN AVG(i.shake) < 5 THEN 1 WHEN AVG(i.shake) < 8 THEN 2 ELSE 3 END as vibration_status FROM inspection i INNER JOIN sensor s ON i.sensor_id = s.id
AND s.pipeline_id = #{pipeId}
AND s.pipe_segment_id = #{segmentId}
AND s.pipe_segment_id IN
#{segmentIdItem}
